import jwt
from Cryptodome import Random
from Cryptodome.PublicKey import RSA

class JWTWrapper:
    def __init__(self, algorithm='HS256'):
        self.algorithm = algorithm
        if self.algorithm == 'RS256':
            self.key = RSA.generate(1024)
            self.keys = {'kid': str(self.key.n), 'e': str(int(self.key.e, 16))}
        else:
            self.key = bytes(b'secret')  # Replace this with your secret key for HS256

    def encode_token(self, payload):
        headers = {'alg': self.algorithm, 'typ': 'JWT'}
        if self.algorithm == 'RS256':
            headers['kid'] = self.keys['kid']

        encoded_headers = jwt.encode(headers, self.key, algorithm=self.algorithm)
        token = jwt.encode(payload, self.key, algorithm=self.algorithm, headers=encoded_headers)
        return token

    def decode_token(self, token):
        try:
            decoded = jwt.decode(token, verify=True, algorithms=[self.algorithm])
            payload = decoded['payload']
            return payload
        except Exception as e:
            print('Error in JWT decoding: ', str(e))
            return None